- ba53b3585d094aceafe698fe8a506ed1:/etc/peakcommerce/support-ops-console/rbac-policy.yml: version: 1
service:
  name: support-ops-console
  environment: prod
  managed_by: helm
  owner_team: commerce-support-platform
  config_scope: rbac-and-audit
  source_of_truth: /etc/peakcommerce/support-ops-console/rbac-policy.yml
identity:
  auth_mode: sso
  idp: enterprise-idp
  mfa_required: true
  session: {max_duration_minutes: 480, idle_timeout_minutes: 30, reauth_for_sensitive_actions: true}
  user_id_claim: sub
  email_claim: email
  groups_claim: groups
audit:
  enabled: true
  sink: {type: kafka, topic: support.audit.events.v1, fallback_log_path: /var/log/peakcommerce/support-ops-console/audit.log}
  correlation:
    required_fields: [correlation_id, actor_user_id, actor_email, actor_role, tenant_id, source_ip, session_id]
    optional_fields: [order_id, cart_id, customer_id, payment_attempt_id, client_request_id, case_id, refund_id, replay_job_id]
  retention: {audit_years: 7, search_index_days: 365}
  redact_fields: [payment_card_pan, payment_card_cvv, auth_token, password, government_id_number]
  immutable_actions: [order.refund.approve, order.refund.execute, order.cancel.execute, workflow.replay.execute, inventory.override.execute, promotion.override.execute, customer.pii.export]
defaults:
  deny_by_default: true
  require_reason_for_sensitive_actions: true
  reason_min_length: 12
  require_ticket_reference_for: [order.refund.approve, order.refund.execute, order.cancel.execute, workflow.replay.execute, inventory.override.execute, promotion.override.execute, customer.pii.export]
  require_order_lookup_scope_validation: true
  enforce_home_region_write_controls: true
  allowed_regions: [ap-southeast-1, ap-northeast-1]
resource_policies:
  order: {source_of_truth: postgresql, searchable_via: [elasticsearch], write_region_rule: tenant_home_region_only}
  payment: {source_of_truth: postgresql, write_region_rule: tenant_home_region_only}
  inventory: {source_of_truth: postgresql, write_region_rule: service_controlled_only}
  support_case: {source_of_truth: postgresql, write_region_rule: active_active_read_write}
  workflow_replay: {source_of_truth: kafka, write_region_rule: controlled_operator_action}
  promotion: {source_of_truth: postgresql, write_region_rule: pricing_team_only}
actions:
  - {id: order.view, description: View order summary timeline and annotations, resource: order, sensitivity: medium, audit_level: standard, requires_mfa_step_up: false}
  - {id: order.search, description: Search orders by identifiers and correlation data, resource: order, sensitivity: medium, audit_level: standard, requires_mfa_step_up: false}
  - {id: order.note.add, description: Add internal support note to order timeline, resource: order, sensitivity: medium, audit_level: standard, requires_mfa_step_up: false}
  - {id: order.cancel.request, description: Submit cancellation request for policy evaluation, resource: order, sensitivity: high, audit_level: elevated, requires_mfa_step_up: true}
  - {id: order.cancel.execute, description: Execute cancellation after policy and state validation, resource: order, sensitivity: critical, audit_level: immutable, requires_mfa_step_up: true}
  - {id: order.refund.request, description: Create refund request within policy limits, resource: payment, sensitivity: high, audit_level: elevated, requires_mfa_step_up: true}
  - {id: order.refund.approve, description: Approve refund request for execution, resource: payment, sensitivity: critical, audit_level: immutable, requires_mfa_step_up: true}
  - {id: order.refund.execute, description: Execute approved refund through integration workflow, resource: payment, sensitivity: critical, audit_level: immutable, requires_mfa_step_up: true}
  - {id: workflow.replay.preview, description: Inspect failed workflow payload and replay eligibility, resource: workflow_replay, sensitivity: high, audit_level: elevated, requires_mfa_step_up: true}
  - {id: workflow.replay.execute, description: Trigger controlled replay from retry queue or DLQ, resource: workflow_replay, sensitivity: critical, audit_level: immutable, requires_mfa_step_up: true}
  - {id: inventory.exception.view, description: View reservation mismatch and oversell exception details, resource: inventory, sensitivity: high, audit_level: elevated, requires_mfa_step_up: false}
  - {id: inventory.override.request, description: Request manual inventory exception override, resource: inventory, sensitivity: critical, audit_level: elevated, requires_mfa_step_up: true}
  - {id: inventory.override.execute, description: Execute approved inventory exception override, resource: inventory, sensitivity: critical, audit_level: immutable, requires_mfa_step_up: true}
  - {id: promotion.override.preview, description: Preview promotion override impact for support remediation, resource: promotion, sensitivity: high, audit_level: elevated, requires_mfa_step_up: true}
  - {id: promotion.override.execute, description: Apply approved one-off promotion remediation, resource: promotion, sensitivity: critical, audit_level: immutable, requires_mfa_step_up: true}
  - {id: customer.pii.view_masked, description: View masked customer contact and address details, resource: customer, sensitivity: high, audit_level: elevated, requires_mfa_step_up: false}
  - {id: customer.pii.export, description: Export customer interaction and order-linked data for dispute handling, resource: customer, sensitivity: critical, audit_level: immutable, requires_mfa_step_up: true}
  - {id: audit.read, description: Read support audit trail for compliance review, resource: audit, sensitivity: high, audit_level: elevated, requires_mfa_step_up: true}
roles:
  - id: support_readonly
    description: Tier-1 support read access for order lookup and customer assistance
    grants: [order.view, order.search, customer.pii.view_masked]
    constraints: {refund_daily_limit_amount: 0, cancellation_allowed: false, replay_allowed: false, inventory_override_allowed: false, promotion_override_allowed: false}
  - id: support_specialist
    description: Tier-2 support with note taking and refund request initiation
    grants: [order.view, order.search, order.note.add, order.cancel.request, order.refund.request, customer.pii.view_masked, workflow.replay.preview, inventory.exception.view]
    constraints: {refund_daily_limit_amount: 2000, refund_single_limit_amount: 250, cancellation_allowed: request_only, replay_allowed: preview_only, inventory_override_allowed: false, promotion_override_allowed: false}
  - id: support_supervisor
    description: Supervisor role for approvals and controlled execution within policy
    grants: [order.view, order.search, order.note.add, order.cancel.request, order.cancel.execute, order.refund.request, order.refund.approve, workflow.replay.preview, customer.pii.view_masked]
    constraints:
      refund_daily_limit_amount: 15000
      refund_single_limit_amount: 1000
      cancellation_allowed: execute
      replay_allowed: preview_only
      inventory_override_allowed: false
      promotion_override_allowed: false
      dual_control_required_for: [order.cancel.execute, order.refund.approve]
  - id: ops_duty_manager
    description: Operations manager for incident remediation and replay execution
    grants: [order.view, order.search, workflow.replay.preview, workflow.replay.execute, inventory.exception.view, inventory.override.request, customer.pii.view_masked]
    constraints:
      refund_daily_limit_amount: 0
      cancellation_allowed: false
      replay_allowed: execute
      inventory_override_allowed: request_only
      promotion_override_allowed: false
      dual_control_required_for: [workflow.replay.execute]
  - id: finance_refund_manager
    description: Finance-controlled refund execution role
    grants: [order.view, order.search, order.refund.request, order.refund.approve, order.refund.execute, customer.pii.view_masked]
    constraints:
      refund_daily_limit_amount: 100000
      refund_single_limit_amount: 5000
      cancellation_allowed: false
      replay_allowed: false
      inventory_override_allowed: false
      promotion_override_allowed: false
      dual_control_required_for: [order.refund.approve, order.refund.execute]
  - id: pricing_operations
    description: Pricing operations role for promotion remediation during campaigns
    grants: [order.view, order.search, promotion.override.preview, promotion.override.execute, customer.pii.view_masked]
    constraints: {refund_daily_limit_amount: 0, cancellation_allowed: false, replay_allowed: false, inventory_override_allowed: false, promotion_override_allowed: execute, dual_control_required_for: [promotion.override.execute]}
  - id: compliance_auditor
    description: Read-only compliance role with audit access
    grants: [order.view, order.search, audit.read, customer.pii.view_masked]
    constraints: {refund_daily_limit_amount: 0, cancellation_allowed: false, replay_allowed: false, inventory_override_allowed: false, promotion_override_allowed: false}
approval_workflows:
  dual_control: {enabled: true, distinct_actors_required: true, actor_must_not_equal_requestor: true, expiry_minutes: 60}
  refund_execution:
    requires_approved_request: true
    allowed_executor_roles: [finance_refund_manager]
    blocked_if_order_state_in: [PAYMENT_VOIDED, REFUND_COMPLETED, FRAUD_HOLD]
  cancellation_execution:
    requires_policy_check: true
    allowed_executor_roles: [support_supervisor]
    blocked_if_order_state_in: [SHIPPED, DELIVERED, REFUND_COMPLETED]
  replay_execution:
    requires_preview: true
    allowed_executor_roles: [ops_duty_manager]
    blocked_topic_patterns: ['*.audit.*']
    blocked_if_dlq_age_hours_gt: 168
  inventory_override_execution: {requires_change_ticket: true, allowed_executor_roles: [], mode: disabled_in_console}
  promotion_override_execution: {requires_change_ticket: true, allowed_executor_roles: [pricing_operations], max_campaign_window_minutes: 1440}
field_level_access:
  customer:
    masked_fields: [email, phone, address_line_1, address_line_2]
    restricted_fields: [full_payment_token, card_fingerprint, fraud_score_raw]
  payment:
    masked_fields: [gateway_reference, authorization_code]
    restricted_fields: [pan, cvv, network_token]
  order:
    restricted_fields: [internal_risk_notes, warehouse_pick_credentials]
group_role_mapping:
  - {group: peakcommerce-support-readonly, role: support_readonly}
  - {group: peakcommerce-support-specialist, role: support_specialist}
  - {group: peakcommerce-support-supervisor, role: support_supervisor}
  - {group: peakcommerce-ops-duty-manager, role: ops_duty_manager}
  - {group: peakcommerce-finance-refund-manager, role: finance_refund_manager}
  - {group: peakcommerce-pricing-operations, role: pricing_operations}
  - {group: peakcommerce-compliance-auditor, role: compliance_auditor}
policy_guards:
  tenant_scope_enforcement: true
  region_scope_enforcement: true
  require_correlation_id_on_mutation: true
  require_case_id_on_support_mutation: true
  require_payment_attempt_id_for_refund_actions: true
  require_client_request_id_for_replay_actions: false
  block_bulk_exports_without_compliance_role: true
  block_manual_actions_during_incident_sev1_except_roles: [ops_duty_manager, compliance_auditor]
break_glass:
  enabled: true
  allowed_roles: [ops_duty_manager]
  max_duration_minutes: 30
  requires_incident_id: true
  requires_reason: true
  extra_audit_tags: [break_glass, sev_incident]
  prohibited_actions: [customer.pii.export, order.refund.execute]
validation:
  config_schema: peakcommerce.supportops.rbac.v1
  fail_on_unknown_action: true
  fail_on_unknown_role: true
  fail_on_duplicate_group_mapping: true
