import com.peakcommerce.order.repository.OrderRepository;
import com.peakcommerce.order.repository.PaymentAttemptRepository;
import com.peakcommerce.order.service.InventoryReservationReleaseService;
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.Timer;
import io.micrometer.observation.annotation.Observed;
import java.time.Clock;
import java.time.Duration;
import java.time.Instant;
import java.util.List;
import java.util.UUID;
import java.util.concurrent.atomic.AtomicBoolean;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;
import org.springframework.transaction.PlatformTransactionManager;
import org.springframework.transaction.support.TransactionTemplate;

@Component
public class ReservationExpiryWorker {

    private static final Logger log = LoggerFactory.getLogger(ReservationExpiryWorker.class);

    private final InventoryReservationRepository reservationRepository;
    private final OrderRepository orderRepository;
    private final PaymentAttemptRepository paymentAttemptRepository;
    private final InventoryReservationReleaseService releaseService;
    private final KafkaTemplate<String, InventoryReservationExpiredEvent> kafkaTemplate;
    private final TransactionTemplate transactionTemplate;
    private final Clock clock;
    private final Counter expiredReservationsCounter;
    private final Counter skippedReservationsCounter;
    private final Counter publishFailureCounter;
    private final Timer batchTimer;
    private final AtomicBoolean running = new AtomicBoolean(false);

    private final int batchSize;
    private final Duration staleSafetyWindow;
    private final String inventoryCompensationTopic;
    private final String workerId;

    public ReservationExpiryWorker(
            InventoryReservationRepository reservationRepository,
            OrderRepository orderRepository,
            PaymentAttemptRepository paymentAttemptRepository,
            InventoryReservationReleaseService releaseService,
            KafkaTemplate<String, InventoryReservationExpiredEvent> kafkaTemplate,
            PlatformTransactionManager transactionManager,
            Clock clock,
            io.micrometer.core.instrument.MeterRegistry meterRegistry,
            @Value("${peakcommerce.reservation-expiry.batch-size:200}") int batchSize,
            @Value("${peakcommerce.reservation-expiry.stale-safety-window:PT30S}") Duration staleSafetyWindow,
            @Value("${peakcommerce.kafka.topics.inventory-compensation:pc.inventory.compensation.v1}") String inventoryCompensationTopic,
            @Value("${HOSTNAME:checkout-order-api}") String workerId) {
        this.reservationRepository = reservationRepository;
        this.orderRepository = orderRepository;
        this.paymentAttemptRepository = paymentAttemptRepository;
        this.releaseService = releaseService;
        this.kafkaTemplate = kafkaTemplate;
        this.transactionTemplate = new TransactionTemplate(transactionManager);
        this.clock = clock;
        this.batchSize = batchSize;
        this.staleSafetyWindow = staleSafetyWindow;
        this.inventoryCompensationTopic = inventoryCompensationTopic;
        this.workerId = workerId;
        this.expiredReservationsCounter = meterRegistry.counter("peakcommerce.reservation.expired.total");
        this.skippedReservationsCounter = meterRegistry.counter("peakcommerce.reservation.expiry.skipped.total");
        this.publishFailureCounter = meterRegistry.counter("peakcommerce.reservation.expiry.publish.failure.total");
        this.batchTimer = meterRegistry.timer("peakcommerce.reservation.expiry.batch.duration");
    }

    @Scheduled(
            initialDelayString = "${peakcommerce.reservation-expiry.initial-delay:15000}",
            fixedDelayString = "${peakcommerce.reservation-expiry.fixed-delay:5000}")
    @Observed(name = "peakcommerce.reservation.expiry.worker")
    public void releaseExpiredReservations() {
        if (!running.compareAndSet(false, true)) {
            log.warn("reservation expiry worker already running, skipping overlapping execution workerId={}", workerId);
            return;
        }

        Instant startedAt = clock.instant();
        Instant expiryCutoff = startedAt.minus(staleSafetyWindow);
        int processed = 0;
        int released = 0;
        int skipped = 0;

        try {
            batchTimer.record(() -> {
                while (true) {
                    List<ExpirableReservationProjection> candidates =
                            reservationRepository.lockNextExpiredReservations(expiryCutoff, batchSize);

                    if (candidates.isEmpty()) {
                        break;
                    }

                    for (ExpirableReservationProjection candidate : candidates) {
                        processed++;
                        try {
                            ExpiryOutcome outcome = expireSingleReservation(candidate, startedAt);
                            if (outcome == ExpiryOutcome.RELEASED) {
                                released++;
                            } else {
                                skipped++;
                            }
                        } catch (Exception ex) {
                            log.error(
                                    "failed to expire reservation reservationId={} orderId={} sku={} workerId={}",
                                    candidate.reservationId(),
                                    candidate.orderId(),
                                    candidate.sku(),
                                    workerId,
                                    ex);
                        }
                    }

                    if (candidates.size() < batchSize) {
                        break;
                    }
                }
            });

            if (processed > 0) {
                log.info(
                        "reservation expiry batch completed workerId={} processed={} released={} skipped={} cutoff={} durationMs={}",
                        workerId,
                        processed,
                        released,
                        skipped,
                        expiryCutoff,
                        Duration.between(startedAt, clock.instant()).toMillis());
            }
        } finally {
            running.set(false);
        }
    }

    private ExpiryOutcome expireSingleReservation(ExpirableReservationProjection candidate, Instant observedAt) {
        return transactionTemplate.execute(status -> {
            ReservationStateSnapshot current =
                    reservationRepository.findStateForUpdate(candidate.reservationId())
                            .orElse(null);

            if (current == null) {
                skippedReservationsCounter.increment();
                log.debug("reservation already absent reservationId={}", candidate.reservationId());
                return ExpiryOutcome.SKIPPED;
            }

            if (!current.isActive()) {
                skippedReservationsCounter.increment();
                log.debug(
                        "reservation not active reservationId={} state={}",
                        current.reservationId(),
                        current.status());
                return ExpiryOutcome.SKIPPED;
            }

            if (current.expiresAt().isAfter(observedAt.minus(staleSafetyWindow))) {
                skippedReservationsCounter.increment();
                log.debug(
                        "reservation no longer expired reservationId={} expiresAt={} observedAt={}",
                        current.reservationId(),
                        current.expiresAt(),
                        observedAt);
                return ExpiryOutcome.SKIPPED;
            }

            boolean orderAlreadyCreated = current.orderId() != null
                    && orderRepository.existsCommittedOrderById(current.orderId());

            boolean paymentAuthorized = current.checkoutSessionId() != null
                    && paymentAttemptRepository.existsSuccessfulAuthorizationForCheckoutSession(current.checkoutSessionId());

            if (orderAlreadyCreated || paymentAuthorized) {
                reservationRepository.markAsConsumed(
                        current.reservationId(),
                        observedAt,
                        "ORDER_OR_PAYMENT_PROGRESS");
                skippedReservationsCounter.increment();
                log.info(
                        "reservation retained due to downstream progress reservationId={} orderId={} checkoutSessionId={} orderAlreadyCreated={} paymentAuthorized={}",
                        current.reservationId(),
                        current.orderId(),
                        current.checkoutSessionId(),
                        orderAlreadyCreated,
                        paymentAuthorized);
                return ExpiryOutcome.SKIPPED;
            }

            releaseService.releaseReservation(
                    current.reservationId(),
                    observedAt,
                    "EXPIRED",
                    "checkout-order-api.reservation-expiry-worker");

            InventoryReservationExpiredEvent event = InventoryReservationExpiredEvent.builder()
                    .eventId(UUID.randomUUID().toString())
                    .reservationId(current.reservationId().toString())
                    .orderId(current.orderId() == null ? null : current.orderId().toString())
                    .checkoutSessionId(current.checkoutSessionId())
                    .customerId(current.customerId())
                    .sku(current.sku())
                    .warehouseCode(current.warehouseCode())
                    .quantity(current.quantity())
                    .expiredAt(observedAt)
                    .reason("RESERVATION_TTL_EXPIRED")
                    .sourceService("checkout-order-api")
                    .sourceRegion("ap-southeast-1")
                    .build();

            try {
                kafkaTemplate.send(inventoryCompensationTopic, current.sku(), event).get();
            } catch (Exception ex) {
                publishFailureCounter.increment();
                throw new ReservationExpiryPublishException(
                        "failed to publish inventory compensation event for reservation " + current.reservationId(), ex);
            }

            expiredReservationsCounter.increment();
            log.info(
                    "expired inventory reservation released reservationId={} orderId={} checkoutSessionId={} sku={} quantity={} warehouseCode={} topic={}",
                    current.reservationId(),
                    current.orderId(),
                    current.checkoutSessionId(),
                    current.sku(),
                    current.quantity(),
                    current.warehouseCode(),
                    inventoryCompensationTopic);

            return ExpiryOutcome.RELEASED;
        });
    }

    private enum ExpiryOutcome {
        RELEASED,
        SKIPPED
    }

    public record ExpirableReservationProjection(
            UUID reservationId,
            UUID orderId,
            String checkoutSessionId,
            String sku) {
    }

    public record ReservationStateSnapshot(
            UUID reservationId,
            UUID orderId,
            String checkoutSessionId,
            String customerId,
            String sku,
            String warehouseCode,
            int quantity,
            String status,
            Instant expiresAt) {

        public boolean isActive() {
            return "ACTIVE".equalsIgnoreCase(status) || "HELD".equalsIgnoreCase(status);
        }
    }

    public static class ReservationExpiryPublishException extends RuntimeException {
        public ReservationExpiryPublishException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
