  };
};

type CacheEntry = { value: PromoBannerResult; expiresAtEpochMs: number; staleAtEpochMs: number };
type PromotionGatewayResponse = { banners: PromoBanner[]; generatedAt: string };
type Logger = {
  info(message: string, fields?: Record<string, unknown>): void;
  warn(message: string, fields?: Record<string, unknown>): void;
  error(message: string, fields?: Record<string, unknown>): void;
};
type Metrics = {
  increment(name: string, tags?: Record<string, string | number | boolean | undefined>): void;
};
type PromotionGateway = {
  fetchEligibleBanners(context: PromoBannerContext): Promise<PromotionGatewayResponse>;
};

const RESOLVER_VERSION = "2026-03-20.5";
const DEFAULT_TIMEOUT_MS = 180;
const MAX_CACHE_ENTRIES = 5000;

export class PromoBannerResolver {
  private readonly cache = new Map<string, CacheEntry>();

  constructor(
    private readonly gateway: PromotionGateway,
    private readonly logger: Logger,
    private readonly metrics: Metrics,
  ) {}

  async resolve(context: PromoBannerContext): Promise<PromoBannerResult> {
    const now = context.now ?? new Date();
    const cacheKey = this.buildCacheKey(context, now);
    const traceHint = this.traceHint(context, cacheKey);
    const cached = this.cache.get(cacheKey);
    const campaignWindow = context.campaignWindow ?? "standard";

    if (cached && cached.expiresAtEpochMs > now.getTime()) {
      this.metrics.increment("storefront_promo_banner_cache_requests_total", {
        status: "hit", region: context.region, campaign_window: campaignWindow,
      });
      return this.withCacheMetadata(cached.value, cacheKey, "hit", "cache", traceHint);
    }

    if (cached && cached.staleAtEpochMs > now.getTime()) {
      this.metrics.increment("storefront_promo_banner_cache_requests_total", {
        status: "stale", region: context.region, campaign_window: campaignWindow,
      });
      this.refreshInBackground(context).catch((error: unknown) => {
        this.logger.warn("promo banner background refresh failed", {
          service: "storefront-web",
          region: context.region,
          cacheKey,
          error: error instanceof Error ? error.message : "unknown",
        });
      });
      return this.withCacheMetadata(cached.value, cacheKey, "stale", "cache", traceHint);
    }

    this.metrics.increment("storefront_promo_banner_cache_requests_total", {
      status: "miss", region: context.region, campaign_window: campaignWindow,
    });

    try {
      const originResult = await this.fetchWithTimeout(context, traceHint);
      this.putCache(cacheKey, originResult, now);
      return originResult;
    } catch (error: unknown) {
      this.metrics.increment("storefront_promo_banner_origin_failures_total", {
        region: context.region, campaign_window: campaignWindow,
      });

      if (cached) {
        this.logger.warn("promo banner origin failed, serving stale banner", {
          service: "storefront-web",
          region: context.region,
          cacheKey,
          traceHint,
