    }
  }

  private withCacheMetadata(
    value: PromoBannerResult,
    key: string,
    status: PromoBannerResult["cache"]["status"],
    selectedFrom: PromoBannerResult["diagnostics"]["selectedFrom"],
    traceHint: string,
  ): PromoBannerResult {
