    };
  }

  private async refreshInBackground(context: PromoBannerContext): Promise<void> {
    const now = context.now ?? new Date();
    const cacheKey = this.buildCacheKey(context, now);
    const refreshed = await this.fetchWithTimeout(context, this.traceHint(context, cacheKey));
    this.putCache(cacheKey, refreshed, now);
  }

  private async fetchWithTimeout(
    context: PromoBannerContext,
    traceHint: string,
  ): Promise<PromoBannerResult> {
    const startedAt = Date.now();
    const timeout = new Promise<never>((_, reject) => {
      setTimeout(() => reject(new Error("promotion gateway timeout")), DEFAULT_TIMEOUT_MS);
    });
    const response = await Promise.race([this.gateway.fetchEligibleBanners(context), timeout]);
    const selected = this.selectBanner(response, context);
    const campaignWindow = context.campaignWindow ?? "standard";

    this.metrics.increment("storefront_promo_banner_origin_requests_total", {
      region: context.region,
      campaign_window: campaignWindow,
      selected: selected ? "true" : "false",
    });

    this.logger.info("promo banner resolved from origin", {
      service: "storefront-web",
      region: context.region,
      durationMs: Date.now() - startedAt,
      traceHint,
      campaignWindow,
      selectedBannerId: selected?.id ?? null,
      quotaState: selected?.quotaState ?? null,
    });

    if (!selected) {
      return this.emptyResult(this.buildCacheKey(context, context.now ?? new Date()), traceHint, "no-active-campaign");
    }

    const ttlSeconds = this.computeTtlSeconds(selected, context);
    return {
      banner: selected,
      cache: {
        key: this.buildCacheKey(context, context.now ?? new Date()),
        status: "miss",
        ttlSeconds,
        scope: this.cacheScope(selected),
      },
      diagnostics: {
        resolverVersion: RESOLVER_VERSION,
        selectedFrom: "origin",
        reason: "eligible",
        traceHint,
      },
    };
  }

  private selectBanner(
    response: PromotionGatewayResponse,
    context: PromoBannerContext,
  ): PromoBanner | null {
    if (!response || !Array.isArray(response.banners)) {
      this.metrics.increment("storefront_promo_banner_invalid_payload_total", { region: context.region });
      return null;
    }

    const now = (context.now ?? new Date()).getTime();
    const segments = new Set(context.segments ?? []);
    const signedIn = Boolean(context.customerId);

    const eligible = response.banners
      .filter((banner) => {
        const starts = Date.parse(banner.startsAt);
        const ends = Date.parse(banner.endsAt);
        if (Number.isNaN(starts) || Number.isNaN(ends) || starts > now || ends <= now) return false;
        if (banner.quotaState === "exhausted") return false;
        if (banner.audience === "signed-in" && !signedIn) return false;
        if (banner.audience === "segment") return (banner.segments ?? []).some((segment) => segments.has(segment));
        return true;
      })
      .sort((a, b) => (a.priority !== b.priority ? b.priority - a.priority : Date.parse(a.endsAt) - Date.parse(b.endsAt)));

    return eligible[0] ?? null;
  }

  private computeTtlSeconds(banner: PromoBanner, context: PromoBannerContext): number {
    const now = context.now ?? new Date();
    const secondsToEnd = Math.max(5, Math.floor((Date.parse(banner.endsAt) - now.getTime()) / 1000));
    if (context.campaignWindow === "flash-sale" || banner.renderHints.theme === "flash-sale") return Math.min(15, secondsToEnd);
    if (banner.quotaState === "limited") return Math.min(30, secondsToEnd);
    return Math.min(Math.max(30, banner.cacheTtlSeconds), secondsToEnd, 180);
  }

  private cacheScope(banner: PromoBanner): "public" | "private" {
    return banner.audience === "all" ? "public" : "private";
  }

  private buildCacheKey(context: PromoBannerContext, now: Date): string {
    const segmentKey = context.segments && context.segments.length > 0 ? [...context.segments].sort().join(",") : "none";
    return [
      "pc",
      "storefront-web",
      "promo-banner",
      context.environment,
      context.region,
      context.channel,
      context.locale,
      context.currency,
      context.campaignWindow ?? "standard",
      context.customerId ? "signed-in" : "guest",
      segmentKey,
      this.timeBucket(context, now),
    ].join(":");
  }

  private timeBucket(context: PromoBannerContext, now: Date): string {
    return `${Math.floor(now.getTime() / (context.campaignWindow === "flash-sale" ? 10000 : 60000))}`;
  }

  private traceHint(context: PromoBannerContext, cacheKey: string): string {
    return crypto
      .createHash("sha256")
      .update(["storefront-web", context.region, context.sessionId, context.cartId ?? "no-cart", cacheKey].join("|"))
      .digest("hex")
      .slice(0, 16);
  }

  private putCache(cacheKey: string, result: PromoBannerResult, now: Date): void {
    if (this.cache.size >= MAX_CACHE_ENTRIES) {
      const oldestKey = this.cache.keys().next().value;
      if (oldestKey) this.cache.delete(oldestKey);
    }
    const ttlMs = result.cache.ttlSeconds * 1000;
    this.cache.set(cacheKey, {
      value: result,
      expiresAtEpochMs: now.getTime() + ttlMs,
      staleAtEpochMs: now.getTime() + ttlMs * 3,
    });
  }

  private emptyResult(
    cacheKey: string,
    traceHint: string,
    reason: PromoBannerResult["diagnostics"]["reason"],
  ): PromoBannerResult {
    return {
      banner: null,
      cache: { key: cacheKey, status: "miss", ttlSeconds: 10, scope: "public" },
      diagnostics: {
        resolverVersion: RESOLVER_VERSION,
        selectedFrom: "origin",
        reason,
        traceHint,
      },
    };
  }
}

export function toCacheControl(result: PromoBannerResult): string {
  const maxAge = Math.max(0, result.cache.ttlSeconds);
  return result.cache.scope === "public"
    ? `public, max-age=${maxAge}, stale-while-revalidate=${maxAge * 2}`
    : `private, max-age=${Math.min(maxAge, 15)}, stale-while-revalidate=30`;
}

export function shouldRenderBanner(result: PromoBannerResult): boolean {
  return Boolean(result.banner) && result.diagnostics.reason === "eligible";
}
