import java.util.UUID;

@Component
public class FlashSaleQuotaGuard {

    private static final Logger log = LoggerFactory.getLogger(FlashSaleQuotaGuard.class);

    private static final DefaultRedisScript<List> RESERVE_SCRIPT = script("""
        local quotaKey = KEYS[1]
        local holdKey = KEYS[2]
        local requestKey = KEYS[3]
        local requested = tonumber(ARGV[1])
        local holdTtlMs = tonumber(ARGV[2])
        local requestTtlMs = tonumber(ARGV[3])
        local requestId = ARGV[4]
        local nowEpochMs = ARGV[5]
        local quota = tonumber(redis.call('GET', quotaKey) or '-1')
        if quota < 0 then return { 'QUOTA_NOT_CONFIGURED', tostring(quota), '0' } end
        local existing = redis.call('GET', requestKey)
        if existing then
            local existingHold = tonumber(redis.call('GET', holdKey) or '0')
            return { 'IDEMPOTENT_REPLAY', tostring(quota), tostring(existingHold) }
        end
        if quota < requested then return { 'INSUFFICIENT_QUOTA', tostring(quota), '0' } end
        local remaining = redis.call('DECRBY', quotaKey, requested)
        if remaining < 0 then
            redis.call('INCRBY', quotaKey, requested)
            local restored = tonumber(redis.call('GET', quotaKey) or '0')
            return { 'RACE_REJECTED', tostring(restored), '0' }
        end
        redis.call('SET', holdKey, requested, 'PX', holdTtlMs)
        redis.call('SET', requestKey, requestId .. ':' .. nowEpochMs, 'PX', requestTtlMs)
        return { 'RESERVED', tostring(remaining), tostring(requested) }
        """);

    private static final DefaultRedisScript<List> CONFIRM_SCRIPT = script("""
        local holdKey = KEYS[1]
        local requestKey = KEYS[2]
        local requestTtlMs = tonumber(ARGV[1])
        local held = tonumber(redis.call('GET', holdKey) or '0')
        if held <= 0 then
            if redis.call('EXISTS', requestKey) == 1 then redis.call('PEXPIRE', requestKey, requestTtlMs) end
            return { 'NO_ACTIVE_HOLD', '0' }
        end
        redis.call('DEL', holdKey)
        if redis.call('EXISTS', requestKey) == 1 then redis.call('PEXPIRE', requestKey, requestTtlMs) end
        return { 'CONFIRMED', tostring(held) }
        """);

    private static final DefaultRedisScript<List> RELEASE_SCRIPT = script("""
        local quotaKey = KEYS[1]
        local holdKey = KEYS[2]
        local requestKey = KEYS[3]
        local requestTtlMs = tonumber(ARGV[1])
        local held = tonumber(redis.call('GET', holdKey) or '0')
        if held <= 0 then
            if redis.call('EXISTS', requestKey) == 1 then redis.call('PEXPIRE', requestKey, requestTtlMs) end
            return { 'NO_ACTIVE_HOLD', '0', tostring(redis.call('GET', quotaKey) or '0') }
        end
        redis.call('DEL', holdKey)
        local remaining = redis.call('INCRBY', quotaKey, held)
        if redis.call('EXISTS', requestKey) == 1 then redis.call('PEXPIRE', requestKey, requestTtlMs) end
        return { 'RELEASED', tostring(held), tostring(remaining) }
        """);

    private final StringRedisTemplate redisTemplate;
    private final Clock clock;
    private final Counter reserveSuccessCounter;
    private final Counter reserveRejectedCounter;
    private final Counter reserveReplayCounter;
    private final Counter releaseCounter;
    private final Counter confirmCounter;
    private final Counter redisFailureCounter;

    public FlashSaleQuotaGuard(StringRedisTemplate redisTemplate, MeterRegistry meterRegistry, Clock clock) {
        this.redisTemplate = redisTemplate;
        this.clock = clock;
        reserveSuccessCounter = meterRegistry.counter("peakcommerce.promotion.flash_sale.reserve.success");
        reserveRejectedCounter = meterRegistry.counter("peakcommerce.promotion.flash_sale.reserve.rejected");
        reserveReplayCounter = meterRegistry.counter("peakcommerce.promotion.flash_sale.reserve.replay");
        releaseCounter = meterRegistry.counter("peakcommerce.promotion.flash_sale.release");
        confirmCounter = meterRegistry.counter("peakcommerce.promotion.flash_sale.confirm");
        redisFailureCounter = meterRegistry.counter("peakcommerce.promotion.flash_sale.redis.failure");
    }

    public ReservationDecision reserve(ReserveCommand command) {
        validate(command);
        String quotaKey = quotaKey(command.campaignId(), command.promotionId());
        String holdKey = holdKey(command.campaignId(), command.promotionId(), command.subjectType(), command.subjectId());
        String requestKey = requestKey(command.campaignId(), command.promotionId(), command.requestId());
        try {
            List<String> result = cast(redisTemplate.execute(
                RESERVE_SCRIPT,
                List.of(quotaKey, holdKey, requestKey),
                Integer.toString(command.units()),
                Long.toString(command.holdTtl().toMillis()),
                Long.toString(command.requestTtl().toMillis()),
                command.requestId(),
                Long.toString(Instant.now(clock).toEpochMilli())
            ));
            String status = get(result, 0);
            long remaining = parseLong(get(result, 1), -1L);
            int heldUnits = (int) parseLong(get(result, 2), 0L);
            if ("RESERVED".equals(status)) {
                reserveSuccessCounter.increment();
                log.info("flash sale quota reserved campaignId={} promotionId={} subjectType={} subjectId={} requestId={} units={} remainingQuota={} holdTtlMs={}",
                    command.campaignId(), command.promotionId(), command.subjectType(), command.subjectId(), command.requestId(),
                    command.units(), remaining, command.holdTtl().toMillis());
                return ReservationDecision.reserved(command.requestId(), heldUnits, remaining, holdKey);
            }
            if ("IDEMPOTENT_REPLAY".equals(status)) {
                reserveReplayCounter.increment();
                log.info("flash sale quota replay detected campaignId={} promotionId={} requestId={} subjectType={} subjectId={} remainingQuota={} heldUnits={}",
                    command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), remaining, heldUnits);
                return ReservationDecision.replayed(command.requestId(), heldUnits, remaining);
            }
            reserveRejectedCounter.increment();
            log.warn("flash sale quota reservation rejected campaignId={} promotionId={} requestId={} subjectType={} subjectId={} reason={} requestedUnits={} remainingQuota={}",
                command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), status, command.units(), remaining);
            return ReservationDecision.rejected(command.requestId(), status, remaining);
        } catch (DataAccessException ex) {
            return redisError("reservation", command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), ex,
                () -> ReservationDecision.error(command.requestId(), "REDIS_ACCESS_ERROR"));
        }
    }

    public CompletionDecision confirm(CompletionCommand command) {
