        String holdKey = holdKey(command.campaignId(), command.promotionId(), command.subjectType(), command.subjectId());
        String requestKey = requestKey(command.campaignId(), command.promotionId(), command.requestId());
        try {
            List<String> result = cast(redisTemplate.execute(
                CONFIRM_SCRIPT,
                List.of(holdKey, requestKey),
                Long.toString(command.requestTtl().toMillis())
            ));
            String status = get(result, 0);
            int units = (int) parseLong(get(result, 1), 0L);
            if ("CONFIRMED".equals(status)) {
                confirmCounter.increment();
                log.info("flash sale quota confirmed campaignId={} promotionId={} requestId={} subjectType={} subjectId={} units={}",
                    command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), units);
