            log.warn("flash sale quota confirm skipped campaignId={} promotionId={} requestId={} subjectType={} subjectId={} reason={}",
                command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), status);
            return CompletionDecision.noop(command.requestId(), status);
        } catch (DataAccessException ex) {
            return redisError("confirm", command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), ex,
                () -> CompletionDecision.error(command.requestId(), "REDIS_ACCESS_ERROR"));
        }
    }

    public ReleaseDecision release(CompletionCommand command) {
        validate(command);
        String quotaKey = quotaKey(command.campaignId(), command.promotionId());
        String holdKey = holdKey(command.campaignId(), command.promotionId(), command.subjectType(), command.subjectId());
        String requestKey = requestKey(command.campaignId(), command.promotionId(), command.requestId());
        try {
            List<String> result = cast(redisTemplate.execute(
                RELEASE_SCRIPT,
                List.of(quotaKey, holdKey, requestKey),
                Long.toString(command.requestTtl().toMillis())
            ));
            String status = get(result, 0);
            int units = (int) parseLong(get(result, 1), 0L);
            long remaining = parseLong(get(result, 2), -1L);
            if ("RELEASED".equals(status)) {
                releaseCounter.increment();
                log.info("flash sale quota released campaignId={} promotionId={} requestId={} subjectType={} subjectId={} units={} remainingQuota={}",
                    command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), units, remaining);
                return ReleaseDecision.released(command.requestId(), units, remaining);
            }
            log.warn("flash sale quota release skipped campaignId={} promotionId={} requestId={} subjectType={} subjectId={} reason={} remainingQuota={}",
                command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), status, remaining);
            return ReleaseDecision.noop(command.requestId(), status, remaining);
        } catch (DataAccessException ex) {
            return redisError("release", command.campaignId(), command.promotionId(), command.requestId(), command.subjectType(), command.subjectId(), ex,
                () -> ReleaseDecision.error(command.requestId(), "REDIS_ACCESS_ERROR"));
        }
