    private void validate(ReserveCommand command) {
        Objects.requireNonNull(command, "command must not be null");
        requireText(command.campaignId(), "campaignId");
        requireText(command.promotionId(), "promotionId");
        requireText(command.subjectType(), "subjectType");
        requireText(command.subjectId(), "subjectId");
        requireText(command.requestId(), "requestId");
        if (command.units() <= 0) throw new IllegalArgumentException("units must be greater than zero");
        requirePositive(command.holdTtl(), "holdTtl");
        requirePositive(command.requestTtl(), "requestTtl");
    }

    private void validate(CompletionCommand command) {
        Objects.requireNonNull(command, "command must not be null");
        requireText(command.campaignId(), "campaignId");
        requireText(command.promotionId(), "promotionId");
        requireText(command.subjectType(), "subjectType");
        requireText(command.subjectId(), "subjectId");
        requireText(command.requestId(), "requestId");
        requirePositive(command.requestTtl(), "requestTtl");
    }

    private static void requireText(String value, String field) {
        if (value == null || value.isBlank()) throw new IllegalArgumentException(field + " must not be blank");
    }

    private static void requirePositive(Duration value, String field) {
        if (value == null || value.isNegative() || value.isZero()) throw new IllegalArgumentException(field + " must be positive");
    }

    private static String quotaKey(String campaignId, String promotionId) {
        return "pc:promo:quota:" + campaignId + ":" + promotionId;
    }

    private static String holdKey(String campaignId, String promotionId, String subjectType, String subjectId) {
        return "pc:promo:hold:" + campaignId + ":" + promotionId + ":" + subjectType + ":" + subjectId;
    }

    private static String requestKey(String campaignId, String promotionId, String requestId) {
        return "pc:promo:req:" + campaignId + ":" + promotionId + ":" + requestId;
    }

    private static DefaultRedisScript<List> script(String lua) {
        DefaultRedisScript<List> script = new DefaultRedisScript<>();
        script.setScriptText(lua);
        script.setResultType(List.class);
        return script;
    }

    @SuppressWarnings("unchecked")
    private static List<String> cast(Object value) {
        return (List<String>) value;
    }

    private static String get(List<String> values, int index) {
        if (values == null || values.size() <= index || values.get(index) == null) return "";
        Object value = values.get(index);
        return value instanceof byte[] bytes ? new String(bytes, StandardCharsets.UTF_8) : String.valueOf(value);
    }

    private static long parseLong(String value, long defaultValue) {
        try {
            return Long.parseLong(value);
        } catch (Exception ex) {
            return defaultValue;
        }
    }

    private <T> T redisError(String action, String campaignId, String promotionId, String requestId, String subjectType,
                             String subjectId, DataAccessException ex, java.util.function.Supplier<T> fallback) {
        redisFailureCounter.increment();
        log.error("flash sale quota {} failed due to redis access error campaignId={} promotionId={} requestId={} subjectType={} subjectId={}",
            action, campaignId, promotionId, requestId, subjectType, subjectId, ex);
        return fallback.get();
    }

    public record ReserveCommand(String campaignId, String promotionId, String subjectType, String subjectId,
                                 String requestId, int units, Duration holdTtl, Duration requestTtl) {
        public static ReserveCommand forCheckout(String campaignId, String promotionId, String customerId,
                                                 String requestId, int units, Duration holdTtl, Duration requestTtl) {
            return new ReserveCommand(campaignId, promotionId, "customer", customerId, requestId, units, holdTtl, requestTtl);
        }

        public static ReserveCommand forSession(String campaignId, String promotionId, String sessionId,
                                                int units, Duration holdTtl, Duration requestTtl) {
            return new ReserveCommand(campaignId, promotionId, "session", sessionId, UUID.randomUUID().toString(), units, holdTtl, requestTtl);
        }
    }

    public record CompletionCommand(String campaignId, String promotionId, String subjectType, String subjectId,
                                    String requestId, Duration requestTtl) {
        public static CompletionCommand forCheckout(String campaignId, String promotionId, String customerId,
                                                    String requestId, Duration requestTtl) {
            return new CompletionCommand(campaignId, promotionId, "customer", customerId, requestId, requestTtl);
        }
    }

    public record ReservationDecision(String requestId, boolean accepted, boolean replay, int heldUnits,
                                      long remainingQuota, String reason, String holdReference) {
        static ReservationDecision reserved(String requestId, int heldUnits, long remainingQuota, String holdReference) {
            return new ReservationDecision(requestId, true, false, heldUnits, remainingQuota, "RESERVED", holdReference);
        }
        static ReservationDecision replayed(String requestId, int heldUnits, long remainingQuota) {
            return new ReservationDecision(requestId, true, true, heldUnits, remainingQuota, "IDEMPOTENT_REPLAY", null);
        }
        static ReservationDecision rejected(String requestId, String reason, long remainingQuota) {
            return new ReservationDecision(requestId, false, false, 0, remainingQuota, reason, null);
        }
        static ReservationDecision error(String requestId, String reason) {
            return new ReservationDecision(requestId, false, false, 0, -1L, reason, null);
        }
    }

    public record CompletionDecision(String requestId, boolean completed, int units, String reason) {
        static CompletionDecision confirmed(String requestId, int units) {
            return new CompletionDecision(requestId, true, units, "CONFIRMED");
        }
        static CompletionDecision noop(String requestId, String reason) {
            return new CompletionDecision(requestId, false, 0, reason);
        }
        static CompletionDecision error(String requestId, String reason) {
            return new CompletionDecision(requestId, false, 0, reason);
        }
    }

    public record ReleaseDecision(String requestId, boolean released, int units, long remainingQuota, String reason) {
        static ReleaseDecision released(String requestId, int units, long remainingQuota) {
            return new ReleaseDecision(requestId, true, units, remainingQuota, "RELEASED");
        }
        static ReleaseDecision noop(String requestId, String reason, long remainingQuota) {
            return new ReleaseDecision(requestId, false, 0, remainingQuota, reason);
        }
        static ReleaseDecision error(String requestId, String reason) {
            return new ReleaseDecision(requestId, false, 0, -1L, reason);
        }
    }
