import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Timer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.Clock;
import java.time.Duration;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.Objects;
import java.util.Optional;

@Service
public class PromotionDecisionService {

    private static final Logger log = LoggerFactory.getLogger(PromotionDecisionService.class);
    private static final BigDecimal ONE_HUNDRED = new BigDecimal("100");
    private static final BigDecimal ZERO = new BigDecimal("0.00");
    private static final int MONEY_SCALE = 2;

    private final PromotionRepository promotionRepository;
    private final PromotionThrottlePolicy throttlePolicy;
    private final Clock clock;
    private final Timer evaluationTimer;
    private final Counter evaluationCounter;
    private final Counter rejectedCounter;
    private final Counter throttledCounter;

    public PromotionDecisionService(PromotionRepository promotionRepository,
                                    PromotionThrottlePolicy throttlePolicy,
                                    MeterRegistry meterRegistry,
                                    Clock clock) {
        this.promotionRepository = promotionRepository;
        this.throttlePolicy = throttlePolicy;
        this.clock = clock;
        this.evaluationTimer = Timer.builder("peakcommerce.promotion.evaluation.duration")
                .description("Promotion decision latency")
                .publishPercentileHistogram()
                .register(meterRegistry);
        this.evaluationCounter = Counter.builder("peakcommerce.promotion.evaluation.total")
                .description("Total promotion evaluations")
                .register(meterRegistry);
        this.rejectedCounter = Counter.builder("peakcommerce.promotion.evaluation.rejected")
                .description("Promotion evaluations rejected by eligibility")
                .register(meterRegistry);
        this.throttledCounter = Counter.builder("peakcommerce.promotion.evaluation.throttled")
                .description("Promotion evaluations throttled under peak load")
                .register(meterRegistry);
    }

    public PromotionDecision evaluate(PromotionRequest request) {
        Objects.requireNonNull(request, "request must not be null");
        Instant startedAt = clock.instant();

        return evaluationTimer.record(() -> {
            evaluationCounter.increment();
            validateRequest(request);

            if (throttlePolicy.shouldThrottle(request.channel(), request.market(), request.customerTier())) {
                throttledCounter.increment();
                log.warn("promotion_evaluation_throttled checkout_id={} order_id={} market={} channel={}",
                        request.checkoutId(), request.orderId(), request.market(), request.channel());
                return PromotionDecision.throttled(
                        request.checkoutId(),
                        request.orderId(),
                        "PEAK_THROTTLE_ACTIVE",
                        startedAt
                );
            }

            List<PromotionDefinition> activePromotions = promotionRepository.findActivePromotions(
                    request.market(),
                    request.currency(),
                    startedAt
            );

            List<AppliedPromotion> applied = new ArrayList<>();
            BigDecimal subtotal = normalizeMoney(request.cartSubtotal());
            BigDecimal runningDiscount = ZERO;

            for (PromotionDefinition promotion : sortPromotions(activePromotions)) {
                EligibilityResult eligibility = evaluateEligibility(promotion, request, subtotal);
                if (!eligibility.eligible()) {
                    rejectedCounter.increment();
                    continue;
                }

                BigDecimal discount = calculateDiscount(promotion, request, subtotal.subtract(runningDiscount));
                if (discount.compareTo(ZERO) <= 0) {
                    continue;
                }

                BigDecimal cappedDiscount = capDiscount(discount, subtotal.subtract(runningDiscount));
                if (cappedDiscount.compareTo(ZERO) <= 0) {
                    continue;
                }

                runningDiscount = runningDiscount.add(cappedDiscount);
                applied.add(new AppliedPromotion(
                        promotion.code(),
                        promotion.name(),
                        promotion.type(),
                        cappedDiscount,
                        eligibility.reason(),
                        promotion.stackable()
                ));

                if (!promotion.stackable()) {
                    break;
                }
            }

            BigDecimal finalDiscount = normalizeMoney(runningDiscount.min(subtotal));
            BigDecimal finalTotal = normalizeMoney(subtotal.subtract(finalDiscount));

            PromotionDecision decision = new PromotionDecision(
                    request.checkoutId(),
                    request.orderId(),
                    request.market(),
                    request.currency(),
                    subtotal,
                    finalDiscount,
                    finalTotal,
                    applied,
                    applied.isEmpty() ? "NO_ELIGIBLE_PROMOTIONS" : "PROMOTIONS_APPLIED",
                    startedAt,
                    Duration.between(startedAt, clock.instant()).toMillis()
            );

            log.info("promotion_decision_complete checkout_id={} order_id={} market={} applied_count={} subtotal={} discount={} total={}",
                    request.checkoutId(),
                    request.orderId(),
                    request.market(),
                    applied.size(),
                    subtotal,
                    finalDiscount,
                    finalTotal);

            return decision;
        });
    }

    private void validateRequest(PromotionRequest request) {
        if (isBlank(request.checkoutId())) {
            throw new IllegalArgumentException("checkoutId is required");
        }
        if (isBlank(request.market())) {
            throw new IllegalArgumentException("market is required");
        }
        if (isBlank(request.currency())) {
            throw new IllegalArgumentException("currency is required");
        }
        if (request.items() == null || request.items().isEmpty()) {
            throw new IllegalArgumentException("at least one cart item is required");
        }
        if (request.cartSubtotal() == null || request.cartSubtotal().compareTo(ZERO) < 0) {
            throw new IllegalArgumentException("cartSubtotal must be non-negative");
        }
    }

    private List<PromotionDefinition> sortPromotions(List<PromotionDefinition> promotions) {
        return promotions.stream()
                .filter(Objects::nonNull)
                .sorted(Comparator
                        .comparing(PromotionDefinition::priority, Comparator.reverseOrder())
                        .thenComparing(PromotionDefinition::code))
                .toList();
    }

    private EligibilityResult evaluateEligibility(PromotionDefinition promotion,
                                                  PromotionRequest request,
                                                  BigDecimal subtotal) {
        if (!promotion.enabled()) {
            return EligibilityResult.ineligible("PROMOTION_DISABLED");
        }

        Instant now = clock.instant();
        if (promotion.startsAt() != null && now.isBefore(promotion.startsAt())) {
            return EligibilityResult.ineligible("PROMOTION_NOT_STARTED");
        }
        if (promotion.endsAt() != null && now.isAfter(promotion.endsAt())) {
            return EligibilityResult.ineligible("PROMOTION_EXPIRED");
        }
        if (!matchesMarket(promotion, request.market())) {
            return EligibilityResult.ineligible("MARKET_MISMATCH");
        }
        if (!matchesChannel(promotion, request.channel())) {
            return EligibilityResult.ineligible("CHANNEL_MISMATCH");
        }
        if (!matchesCoupon(promotion, request.couponCode())) {
            return EligibilityResult.ineligible("COUPON_REQUIRED_OR_INVALID");
        }
        if (!meetsMinimumSubtotal(promotion, subtotal)) {
            return EligibilityResult.ineligible("MIN_SUBTOTAL_NOT_MET");
        }
        if (!containsEligibleSku(promotion, request.items())) {
            return EligibilityResult.ineligible("NO_ELIGIBLE_ITEMS");
        }
        if (!matchesCustomerTier(promotion, request.customerTier())) {
            return EligibilityResult.ineligible("CUSTOMER_TIER_MISMATCH");
        }
        return EligibilityResult.eligible("ELIGIBLE");
    }

    private BigDecimal calculateDiscount(PromotionDefinition promotion,
                                         PromotionRequest request,
                                         BigDecimal discountableSubtotal) {
        if (discountableSubtotal.compareTo(ZERO) <= 0) {
            return ZERO;
        }

        return switch (promotion.type()) {
            case PERCENTAGE -> percentageDiscount(discountableSubtotal, promotion.discountValue(), promotion.maxDiscountAmount());
            case FIXED_AMOUNT -> fixedAmountDiscount(promotion.discountValue(), discountableSubtotal);
            case BUY_X_GET_Y -> buyXGetYDiscount(promotion, request.items(), discountableSubtotal);
        };
    }

    private BigDecimal percentageDiscount(BigDecimal subtotal,
                                          BigDecimal percentage,
                                          BigDecimal maxDiscountAmount) {
        if (percentage == null || percentage.compareTo(ZERO) <= 0) {
            return ZERO;
        }
        BigDecimal raw = subtotal.multiply(percentage).divide(ONE_HUNDRED, MONEY_SCALE, RoundingMode.HALF_UP);
        if (maxDiscountAmount != null && maxDiscountAmount.compareTo(ZERO) > 0) {
            return normalizeMoney(raw.min(maxDiscountAmount));
        }
        return normalizeMoney(raw);
    }

    private BigDecimal fixedAmountDiscount(BigDecimal amount, BigDecimal subtotal) {
        if (amount == null || amount.compareTo(ZERO) <= 0) {
            return ZERO;
        }
        return normalizeMoney(amount.min(subtotal));
    }

    private BigDecimal buyXGetYDiscount(PromotionDefinition promotion,
                                        List<CartItem> items,
                                        BigDecimal subtotal) {
        Map<String, String> attrs = Optional.ofNullable(promotion.attributes()).orElse(Map.of());
        int buyQty = parseInt(attrs.get("buy_qty"), 0);
        int freeQty = parseInt(attrs.get("free_qty"), 0);
        if (buyQty <= 0 || freeQty <= 0) {
            return ZERO;
        }

        List<CartItem> eligibleItems = items.stream()
                .filter(item -> item != null && item.quantity() > 0)
                .filter(item -> promotion.eligibleSkus() == null || promotion.eligibleSkus().isEmpty() || promotion.eligibleSkus().contains(item.sku()))
                .sorted(Comparator.comparing(CartItem::unitPrice))
                .toList();

        int totalQty = eligibleItems.stream().mapToInt(CartItem::quantity).sum();
        int bundleSize = buyQty + freeQty;
        int freeUnits = (totalQty / bundleSize) * freeQty;
        if (freeUnits <= 0) {
            return ZERO;
        }

        BigDecimal discount = ZERO;
        int remaining = freeUnits;
        for (CartItem item : eligibleItems) {
            if (remaining <= 0) {
                break;
            }
            int appliedUnits = Math.min(item.quantity(), remaining);
            discount = discount.add(item.unitPrice().multiply(BigDecimal.valueOf(appliedUnits)));
            remaining -= appliedUnits;
        }

        return normalizeMoney(discount.min(subtotal));
    }

    private BigDecimal capDiscount(BigDecimal discount, BigDecimal remainingSubtotal) {
        if (discount == null || remainingSubtotal == null) {
            return ZERO;
        }
        if (remainingSubtotal.compareTo(ZERO) <= 0) {
            return ZERO;
        }
        return normalizeMoney(discount.min(remainingSubtotal));
    }

    private boolean matchesMarket(PromotionDefinition promotion, String market) {
        return promotion.markets() == null
                || promotion.markets().isEmpty()
                || promotion.markets().stream().anyMatch(m -> equalsIgnoreCase(m, market));
    }

    private boolean matchesChannel(PromotionDefinition promotion, String channel) {
        return promotion.channels() == null
                || promotion.channels().isEmpty()
                || promotion.channels().stream().anyMatch(c -> equalsIgnoreCase(c, channel));
    }

    private boolean matchesCoupon(PromotionDefinition promotion, String couponCode) {
        if (!promotion.requiresCoupon()) {
            return true;
        }
        return !isBlank(couponCode) && equalsIgnoreCase(promotion.couponCode(), couponCode);
    }

    private boolean meetsMinimumSubtotal(PromotionDefinition promotion, BigDecimal subtotal) {
        return promotion.minimumSubtotal() == null || subtotal.compareTo(promotion.minimumSubtotal()) >= 0;
    }

    private boolean containsEligibleSku(PromotionDefinition promotion, List<CartItem> items) {
        if (promotion.eligibleSkus() == null || promotion.eligibleSkus().isEmpty()) {
            return true;
        }
        return items.stream()
                .filter(Objects::nonNull)
                .map(CartItem::sku)
                .filter(Objects::nonNull)
                .anyMatch(promotion.eligibleSkus()::contains);
    }

    private boolean matchesCustomerTier(PromotionDefinition promotion, String customerTier) {
        if (promotion.customerTiers() == null || promotion.customerTiers().isEmpty()) {
            return true;
        }
        return promotion.customerTiers().stream().anyMatch(t -> equalsIgnoreCase(t, customerTier));
    }

    private BigDecimal normalizeMoney(BigDecimal value) {
        if (value == null) {
            return ZERO;
        }
        return value.max(ZERO).setScale(MONEY_SCALE, RoundingMode.HALF_UP);
    }

    private boolean equalsIgnoreCase(String left, String right) {
        return left != null && right != null && left.toLowerCase(Locale.ROOT).equals(right.toLowerCase(Locale.ROOT));
    }

    private boolean isBlank(String value) {
        return value == null || value.isBlank();
    }

    private int parseInt(String value, int fallback) {
        try {
            return value == null ? fallback : Integer.parseInt(value);
        } catch (NumberFormatException ex) {
            return fallback;
        }
    }

    private record EligibilityResult(boolean eligible, String reason) {
        static EligibilityResult eligible(String reason) {
            return new EligibilityResult(true, reason);
        }

        static EligibilityResult ineligible(String reason) {
            return new EligibilityResult(false, reason);
        }
    }
}
