public class OrderStateMachine {

    private static final Duration PAYMENT_CONFIRMATION_HOLD_TTL = Duration.ofMinutes(3);
    private static final Duration FULFILLMENT_ACK_TIMEOUT = Duration.ofMinutes(15);

    private final Clock clock;
    private final Map<OrderState, Set<OrderState>> transitions;

    public OrderStateMachine(Clock clock) {
        this.clock = Objects.requireNonNull(clock, "clock");
        this.transitions = buildTransitions();
    }

    public TransitionResult apply(OrderAggregate order, OrderEvent event) {
        Objects.requireNonNull(order, "order");
        Objects.requireNonNull(event, "event");

        if (order.isTerminal() && !event.type().isAdministrative()) {
            return TransitionResult.rejected(order.state(), order.state(), "terminal_state_no_further_domain_events",
