            case PAYMENT_CAPTURE_FAILED -> onPaymentCaptureFailed(order, event);
            case PAYMENT_TIMEOUT_EXPIRED -> onPaymentTimeoutExpired(order, event);
            case INVENTORY_RESERVED -> onInventoryReserved(order, event);
            case INVENTORY_RESERVATION_FAILED -> onInventoryReservationFailed(order, event);
            case INVENTORY_RELEASED -> onInventoryReleased(order, event);
