                Action.scheduleTimeout("payment-confirmation-timeout", event.occurredAt().plus(PAYMENT_CONFIRMATION_HOLD_TTL)),
                o -> o.markPaymentHoldExpiresAt(event.occurredAt().plus(PAYMENT_CONFIRMATION_HOLD_TTL)));
    }

    private TransitionResult onPaymentAuthorized(OrderAggregate order, OrderEvent event) {
        if (order.state() != OrderState.PENDING_PAYMENT) return reject(order, event, "payment_authorized_requires_pending_payment");
        return transition(order, event, OrderState.PAYMENT_AUTHORIZED, null, "payment_authorized",
                Action.emitDomainEvent("order.payment_authorized"),
