        return transition(order, event, target, null, auditCode.toLowerCase(),
                Action.emitDomainEvent(domainEvent),
                releaseInventory ? Action.releaseInventoryIfPresent(order.orderId()) : null,
                Action.recordAudit(auditCode, event.actor()));
    }

    private TransitionResult onPaymentCaptured(OrderAggregate order, OrderEvent event) {
