            return reject(order, event, "payment_capture_requires_inventory_reserved_or_fulfillment_pending");
        }
        OrderState source = order.state();
        order.transitionTo(OrderState.FULFILLMENT_PENDING, event.occurredAt());
        order.markFulfillmentAckDeadline(event.occurredAt().plus(FULFILLMENT_ACK_TIMEOUT));
        add(order, Action.emitDomainEvent("order.payment_captured"), Action.routeToFulfillment(order.orderId(), order.homeRegion()));
