    }

    private TransitionResult onPaymentCaptureFailed(OrderAggregate order, OrderEvent event) {
        if (order.state() != OrderState.INVENTORY_RESERVED && order.state() != OrderState.FULFILLMENT_PENDING) {
            return reject(order, event, "payment_capture_failure_requires_inventory_reserved_or_fulfillment_pending");
        }
