        return TransitionResult.accepted(source, OrderState.CANCELLED, "payment_capture_failed_compensated");
    }

    private TransitionResult onPaymentTimeoutExpired(OrderAggregate order, OrderEvent event) {
        if (order.state() != OrderState.PENDING_PAYMENT) return reject(order, event, "payment_timeout_requires_pending_payment");
