        return TransitionResult.accepted(OrderState.PENDING_PAYMENT, OrderState.EXPIRED, "payment_timeout_expired");
    }

    private TransitionResult onInventoryReserved(OrderAggregate order, OrderEvent event) {
        if (order.state() != OrderState.PAYMENT_AUTHORIZED) return reject(order, event, "inventory_reserved_requires_payment_authorized");
        return transition(order, event, OrderState.INVENTORY_RESERVED, null, "inventory_reserved",
                Action.emitDomainEvent("order.inventory_reserved"),
                Action.capturePayment(order.orderId(), order.homeRegion()));
