        return TransitionResult.accepted(source, OrderState.CANCELLED, "support_cancel_approved");
    }

    private TransitionResult onRefundApproved(OrderAggregate order, OrderEvent event) {
        if (!event.type().isAdministrative()) return reject(order, event, "refund_approval_requires_administrative_event");
        if (order.state() != OrderState.CANCELLED && order.state() != OrderState.DELIVERED && order.state() != OrderState.SHIPPED) {
            return reject(order, event, "refund_approval_requires_cancelled_shipped_or_delivered");
        }
        OrderState source = order.state();
        order.transitionTo(OrderState.REFUND_PENDING, event.occurredAt());
        add(order, Action.refundPayment(order.orderId()), Action.emitDomainEvent("order.refund_pending"),
                Action.recordAudit("REFUND_APPROVED", event.actor()));
        return TransitionResult.accepted(source, OrderState.REFUND_PENDING, "refund_approved");
    }

    private TransitionResult onRefundCompleted(OrderAggregate order, OrderEvent event) {
        if (order.state() != OrderState.REFUND_PENDING) return reject(order, event, "refund_completed_requires_refund_pending");
        return transition(order, event, OrderState.REFUNDED, null, "refund_completed",
                Action.emitDomainEvent("order.refunded"), Action.recordAudit("REFUND_COMPLETED", event.actor()));
    }

    private TransitionResult onAddressOverrideApproved(OrderAggregate order, OrderEvent event) {
        if (!event.type().isAdministrative()) return reject(order, event, "address_override_requires_administrative_event");
        if (order.state() == OrderState.SHIPPED || order.state() == OrderState.DELIVERED) {
            return reject(order, event, "address_override_not_allowed_after_shipment");
        }
        add(order, Action.emitDomainEvent("order.address_override_approved"), Action.recordAudit("ADDRESS_OVERRIDE_APPROVED", event.actor()));
        return TransitionResult.accepted(order.state(), order.state(), "address_override_recorded");
    }

    private TransitionResult onManualRetryRequested(OrderAggregate order, OrderEvent event) {
        if (!event.type().isAdministrative()) return reject(order, event, "manual_retry_requires_administrative_event");
