    private TransitionResult move(OrderAggregate order, OrderEvent event, OrderState required, OrderState target,
                                  String rejectCode, String domainEvent, String resultCode) {
        if (order.state() != required) return reject(order, event, rejectCode);
        return transition(order, event, target, null, resultCode, Action.emitDomainEvent(domainEvent));
    }

    private TransitionResult transition(OrderAggregate order, OrderEvent event, OrderState target, String transitionRejectCode,
                                        String resultCode, Action... actions) {
        OrderState source = order.state();
