        add(order, actions);
        return TransitionResult.accepted(source, target, resultCode);
    }

    private void add(OrderAggregate order, Action... actions) {
        for (Action action : actions) if (action != null) order.addAction(action);
    }

    private TransitionResult reject(OrderAggregate order, OrderEvent event, String reason) {
        return TransitionResult.rejected(order.state(), order.state(), reason,
                "Rejected event " + event.type() + " for state " + order.state());
    }

    private boolean canTransition(OrderState source, OrderState target) {
        return transitions.getOrDefault(source, Set.of()).contains(target);
    }

    private Map<OrderState, Set<OrderState>> buildTransitions() {
        Map<OrderState, Set<OrderState>> map = new EnumMap<>(OrderState.class);
        map.put(OrderState.NEW, EnumSet.of(OrderState.PENDING_PAYMENT));
        map.put(OrderState.PENDING_PAYMENT, EnumSet.of(OrderState.PAYMENT_AUTHORIZED, OrderState.FAILED, OrderState.EXPIRED, OrderState.CANCELLED));
        map.put(OrderState.PAYMENT_AUTHORIZED, EnumSet.of(OrderState.INVENTORY_RESERVED, OrderState.CANCELLED));
        map.put(OrderState.INVENTORY_RESERVED, EnumSet.of(OrderState.FULFILLMENT_PENDING, OrderState.CANCELLED));
        map.put(OrderState.FULFILLMENT_PENDING, EnumSet.of(OrderState.FULFILLMENT_ACCEPTED, OrderState.CANCELLED));
        map.put(OrderState.FULFILLMENT_ACCEPTED, EnumSet.of(OrderState.SHIPPED, OrderState.CANCELLED));
        map.put(OrderState.SHIPPED, EnumSet.of(OrderState.DELIVERED, OrderState.REFUND_PENDING));
        map.put(OrderState.DELIVERED, EnumSet.of(OrderState.REFUND_PENDING));
        map.put(OrderState.CANCELLED, EnumSet.of(OrderState.REFUND_PENDING));
        map.put(OrderState.REFUND_PENDING, EnumSet.of(OrderState.REFUNDED));
        map.put(OrderState.FAILED, EnumSet.of(OrderState.PENDING_PAYMENT));
        map.put(OrderState.EXPIRED, EnumSet.noneOf(OrderState.class));
        map.put(OrderState.REFUNDED, EnumSet.noneOf(OrderState.class));
        return map;
    }

    private boolean isBlank(String value) {
        return value == null || value.isBlank();
    }
