import com.fasterxml.jackson.databind.ObjectMapper;
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;
import java.time.Clock;
import java.time.Duration;
import java.time.Instant;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.dao.OptimisticLockingFailureException;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.stereotype.Component;

@Component
public class StockUpdateConsumer {

    private static final Logger log = LoggerFactory.getLogger(StockUpdateConsumer.class);
    private static final Set<String> SUPPORTED_EVENT_TYPES = Set.of(
        "warehouse.stock-adjusted", "warehouse.receipt-posted", "warehouse.shipment-confirmed",
        "order.inventory-reserved", "order.inventory-released", "order.cancelled", "erp.inventory-correction"
    );

    private final ObjectMapper objectMapper;
    private final InventoryServices services;
    private final Clock clock;
    private final Counter processedCounter;
    private final Counter skippedDuplicateCounter;
    private final Counter unsupportedCounter;
    private final Counter failedCounter;
    private final Counter oversellBlockedCounter;

    public StockUpdateConsumer(
        ObjectMapper objectMapper,
        InventoryLedgerService inventoryLedgerService,
        InventoryProjectionService inventoryProjectionService,
        InventoryEventDeduplicationService deduplicationService,
        OversellProtectionService oversellProtectionService,
        DeadLetterPublisher deadLetterPublisher,
        MeterRegistry meterRegistry,
        Clock clock
    ) {
        this.objectMapper = objectMapper;
        this.services = new InventoryServices(
            inventoryLedgerService,
            inventoryProjectionService,
            deduplicationService,
            oversellProtectionService,
            deadLetterPublisher
        );
        this.clock = clock;
        this.processedCounter = meterRegistry.counter("peakcommerce.inventory.events.processed");
        this.skippedDuplicateCounter = meterRegistry.counter("peakcommerce.inventory.events.duplicate_skipped");
        this.unsupportedCounter = meterRegistry.counter("peakcommerce.inventory.events.unsupported");
        this.failedCounter = meterRegistry.counter("peakcommerce.inventory.events.failed");
        this.oversellBlockedCounter = meterRegistry.counter("peakcommerce.inventory.events.oversell_blocked");
    }

    @KafkaListener(
        id = "inventory-sync-stock-update-consumer",
        topics = {
            "${peakcommerce.kafka.topics.warehouse-events:pc.warehouse.events}",
            "${peakcommerce.kafka.topics.order-events:pc.order.events}",
            "${peakcommerce.kafka.topics.erp-events:pc.erp.inventory.events}"
        },
        containerFactory = "inventoryKafkaListenerContainerFactory"
    )
    public void onMessage(ConsumerRecord<String, String> record, Acknowledgment acknowledgment) {
        Instant startedAt = clock.instant();
        try {
            InventoryEventEnvelope envelope = objectMapper.readValue(record.value(), InventoryEventEnvelope.class);
            InventoryMutation mutation = validateAndBuildMutation(record, envelope);
            if (mutation == null) {
                acknowledgment.acknowledge();
                return;
            }
            processMutation(record, mutation, startedAt);
            acknowledgment.acknowledge();
        } catch (DuplicateEventRaceConditionException ex) {
            skippedDuplicateCounter.increment();
            log.info("Duplicate event race resolved topic={} partition={} offset={} message={}",
                record.topic(), record.partition(), record.offset(), ex.getMessage());
            acknowledgment.acknowledge();
        } catch (UnsupportedInventoryEventException | IllegalArgumentException ex) {
            failedCounter.increment();
            publishToDeadLetter(record, ex, "validation_failure");
            acknowledgment.acknowledge();
        } catch (OversellProtectionException ex) {
            oversellBlockedCounter.increment();
            failedCounter.increment();
            publishToDeadLetter(record, ex, "oversell_protection_block");
            acknowledgment.acknowledge();
        } catch (OptimisticLockingFailureException ex) {
            failedCounter.increment();
            log.warn("Optimistic locking failure for inventory projection topic={} partition={} offset={} error={}",
                record.topic(), record.partition(), record.offset(), ex.getMessage());
            throw ex;
        } catch (Exception ex) {
            failedCounter.increment();
            log.error("Unhandled inventory event processing failure topic={} partition={} offset={} error={}",
                record.topic(), record.partition(), record.offset(), ex.getMessage(), ex);
            throw new InventoryEventProcessingException("Unhandled inventory event processing failure", ex);
        }
    }

    private InventoryMutation validateAndBuildMutation(ConsumerRecord<String, String> record, InventoryEventEnvelope envelope) {
        String eventId = require(envelope.eventId(), "eventId");
        String eventType = require(envelope.eventType(), "eventType");
        String source = require(envelope.source(), "source");
        String sku = require(envelope.sku(), "sku");
        String locationCode = require(envelope.locationCode(), "locationCode");

        if (!SUPPORTED_EVENT_TYPES.contains(eventType)) {
            unsupportedCounter.increment();
            log.warn("Ignoring unsupported inventory event type={} eventId={} topic={} partition={} offset={} source={}",
                eventType, eventId, record.topic(), record.partition(), record.offset(), source);
            return null;
        }
        if (services.deduplicationService().isProcessed(eventId)) {
            skippedDuplicateCounter.increment();
            log.info("Skipping duplicate inventory event eventId={} type={} sku={} location={} topic={} partition={} offset={}",
                eventId, eventType, sku, locationCode, record.topic(), record.partition(), record.offset());
            return null;
        }

        InventoryMutation mutation = toMutation(envelope);
        validateBusinessRules(mutation);
        return mutation;
    }

    private void processMutation(ConsumerRecord<String, String> record, InventoryMutation mutation, Instant startedAt) {
        services.ledgerService().append(mutation);
        InventoryProjection current = services.projectionService().getOrCreate(mutation.sku(), mutation.locationCode());
        InventoryProjection updated = applyMutation(current, mutation);
        services.projectionService().save(updated);
        services.deduplicationService().markProcessed(
            mutation.eventId(), mutation.occurredAt(), record.topic(), record.partition(), record.offset()
        );
        processedCounter.increment();
        log.info("Applied inventory event eventId={} type={} sku={} location={} deltaOnHand={} deltaReserved={} sellableAfter={} reservedAfter={} topic={} partition={} offset={} latencyMs={}",
            mutation.eventId(), mutation.eventType(), mutation.sku(), mutation.locationCode(), mutation.deltaOnHand(),
            mutation.deltaReserved(), updated.sellableQuantity(), updated.reservedQuantity(), record.topic(),
            record.partition(), record.offset(), Duration.between(startedAt, clock.instant()).toMillis());
    }

    private InventoryMutation toMutation(InventoryEventEnvelope envelope) {
        Instant occurredAt = Optional.ofNullable(envelope.occurredAt()).orElse(clock.instant());
        Map<String, Object> attributes = Optional.ofNullable(envelope.attributes()).orElse(Map.of());
        return switch (envelope.eventType()) {
            case "warehouse.stock-adjusted" -> mutation(envelope, occurredAt, attributes, asLong(attributes, "deltaOnHand"), 0L);
            case "warehouse.receipt-posted" -> mutation(envelope, occurredAt, attributes, positive(attributes, "receivedQuantity"), 0L);
            case "warehouse.shipment-confirmed" -> mutation(envelope, occurredAt, attributes, -positive(attributes, "shippedQuantity"), 0L);
            case "order.inventory-reserved" -> mutation(envelope, occurredAt, attributes, 0L, positive(attributes, "reservedQuantity"));
            case "order.inventory-released", "order.cancelled" -> mutation(envelope, occurredAt, attributes, 0L, -positive(attributes, "releasedQuantity"));
            case "erp.inventory-correction" -> mutation(envelope, occurredAt, attributes,
                asLong(attributes, "deltaOnHand"), asLong(attributes, "deltaReserved"));
            default -> throw new UnsupportedInventoryEventException("Unsupported event type: " + envelope.eventType());
        };
    }

    private InventoryMutation mutation(
        InventoryEventEnvelope envelope,
        Instant occurredAt,
        Map<String, Object> attributes,
        long deltaOnHand,
        long deltaReserved
    ) {
        return new InventoryMutation(
            envelope.eventId(), envelope.eventType(), envelope.source(), envelope.sku(), envelope.locationCode(),
            deltaOnHand, deltaReserved, occurredAt, envelope.correlationId(), envelope.traceId(), attributes
        );
    }

    private void validateBusinessRules(InventoryMutation mutation) {
        if (mutation.occurredAt().isAfter(clock.instant().plus(Duration.ofMinutes(2)))) {
            throw new IllegalArgumentException("Event occurredAt is too far in the future");
        }
        if (mutation.eventType().startsWith("order.") && isBlank(mutation.correlationId())) {
            throw new IllegalArgumentException("Order inventory events require correlationId");
        }
        if (mutation.deltaOnHand() == 0 && mutation.deltaReserved() == 0) {
            throw new IllegalArgumentException("Inventory mutation cannot be a no-op");
        }
    }

    private InventoryProjection applyMutation(InventoryProjection current, InventoryMutation mutation) {
        long nextOnHand = current.onHandQuantity() + mutation.deltaOnHand();
        long nextReserved = current.reservedQuantity() + mutation.deltaReserved();
        if (nextOnHand < 0) {
            throw new OversellProtectionException("On-hand inventory cannot become negative for sku=%s location=%s"
                .formatted(mutation.sku(), mutation.locationCode()));
        }
        if (nextReserved < 0) {
            throw new OversellProtectionException("Reserved inventory cannot become negative for sku=%s location=%s"
                .formatted(mutation.sku(), mutation.locationCode()));
        }
        services.oversellProtectionService().assertSellableFloor(
            mutation.sku(), mutation.locationCode(), nextOnHand, nextReserved, mutation.eventType(), mutation.eventId()
        );
        return current.withUpdatedQuantities(
            nextOnHand, nextReserved, mutation.occurredAt(), mutation.eventId(), mutation.eventType()
        );
    }

    private void publishToDeadLetter(ConsumerRecord<String, String> record, Exception ex, String reason) {
        try {
            services.deadLetterPublisher().publish(
                record.topic(), record.partition(), record.offset(), record.key(), record.value(), reason,
                ex.getClass().getSimpleName(), ex.getMessage()
            );
            log.error("Published inventory event to dead-letter topic={} partition={} offset={} reason={} error={}",
                record.topic(), record.partition(), record.offset(), reason, ex.getMessage());
        } catch (Exception dlqEx) {
            log.error("Failed to publish inventory event to dead-letter topic={} partition={} offset={} reason={} error={}",
                record.topic(), record.partition(), record.offset(), reason, dlqEx.getMessage(), dlqEx);
            throw new InventoryEventProcessingException("Dead-letter publish failed", dlqEx);
        }
    }

    private String require(String value, String field) {
        if (isBlank(value)) {
            throw new IllegalArgumentException("Missing required field: " + field);
        }
        return value;
    }

    private boolean isBlank(String value) {
        return value == null || value.isBlank();
    }

    private long positive(Map<String, Object> attributes, String key) {
        long value = asLong(attributes, key);
        if (value <= 0) {
            throw new IllegalArgumentException("Expected positive numeric attribute: " + key);
        }
        return value;
    }

    private long asLong(Map<String, Object> attributes, String key) {
        Object value = attributes.get(key);
        if (value == null) {
            throw new IllegalArgumentException("Missing numeric attribute: " + key);
        }
        if (value instanceof Number number) {
            return number.longValue();
        }
        if (value instanceof String text) {
            return Long.parseLong(text);
        }
        throw new IllegalArgumentException("Unsupported numeric attribute type for key: " + key);
    }

    public record InventoryEventEnvelope(
        String eventId,
        String eventType,
        String source,
        String sku,
        String locationCode,
        Instant occurredAt,
        String correlationId,
        String traceId,
        Map<String, Object> attributes
    ) {}

    public record InventoryMutation(
        String eventId,
        String eventType,
        String source,
        String sku,
        String locationCode,
        long deltaOnHand,
        long deltaReserved,
        Instant occurredAt,
        String correlationId,
        String traceId,
        Map<String, Object> attributes
    ) {}

    public record InventoryProjection(
        String sku,
        String locationCode,
        long onHandQuantity,
        long reservedQuantity,
        long sellableQuantity,
        Instant lastEventAt,
        String lastEventId,
        String lastEventType
    ) {
        public InventoryProjection withUpdatedQuantities(
            long nextOnHand,
            long nextReserved,
            Instant nextEventAt,
            String nextEventId,
            String nextEventType
        ) {
            return new InventoryProjection(
                sku, locationCode, nextOnHand, nextReserved, nextOnHand - nextReserved,
                nextEventAt, nextEventId, nextEventType
            );
        }
    }

    public record InventoryServices(
        InventoryLedgerService ledgerService,
        InventoryProjectionService projectionService,
        InventoryEventDeduplicationService deduplicationService,
        OversellProtectionService oversellProtectionService,
        DeadLetterPublisher deadLetterPublisher
    ) {}

    public interface InventoryLedgerService { void append(InventoryMutation mutation); }
    public interface InventoryProjectionService {
        InventoryProjection getOrCreate(String sku, String locationCode);
        void save(InventoryProjection projection);
    }
    public interface InventoryEventDeduplicationService {
        boolean isProcessed(String eventId);
        void markProcessed(String eventId, Instant occurredAt, String topic, int partition, long offset);
    }
    public interface OversellProtectionService {
        void assertSellableFloor(String sku, String locationCode, long nextOnHand, long nextReserved, String eventType, String eventId);
    }
    public interface DeadLetterPublisher {
        void publish(String sourceTopic, int sourcePartition, long sourceOffset, String key, String payload,
                     String reason, String errorType, String errorMessage);
    }

    public static class InventoryEventProcessingException extends RuntimeException {
        public InventoryEventProcessingException(String message, Throwable cause) { super(message, cause); }
    }
    public static class UnsupportedInventoryEventException extends RuntimeException {
        public UnsupportedInventoryEventException(String message) { super(message); }
    }
    public static class OversellProtectionException extends RuntimeException {
        public OversellProtectionException(String message) { super(message); }
    }
    public static class DuplicateEventRaceConditionException extends RuntimeException {
        public DuplicateEventRaceConditionException(String message) { super(message); }
