import com.peakcommerce.checkout.api.SubmitOrderResponse;
import com.peakcommerce.checkout.service.IdempotencyService;
import com.peakcommerce.checkout.service.OrderSubmissionService;
import com.peakcommerce.checkout.service.model.IdempotencyDecision;
import com.peakcommerce.checkout.service.model.OrderSubmissionResult;
import io.micrometer.common.util.StringUtils;
import io.opentelemetry.api.trace.Span;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import jakarta.validation.constraints.NotBlank;
import java.net.URI;
import java.time.OffsetDateTime;
import java.util.Map;
import java.util.Optional;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
