apiVersion: argoproj.io/v1alpha1
kind: Application
metadata:
  name: peakcommerce-prod-core
  namespace: argocd
  labels:
    business: peakcommerce-enterprise-suite
    environment: prod
    region-mode: active-active
  annotations:
    notifications.argoproj.io/subscribe.on-sync-succeeded.slack: sre-prod-deployments
    notifications.argoproj.io/subscribe.on-sync-failed.slack: sre-prod-alerts
    notifications.argoproj.io/subscribe.on-health-degraded.slack: sre-prod-alerts
spec:
  project: peakcommerce-prod
  destination:
    server: https://kubernetes.default.svc
    namespace: peakcommerce-prod
  source:
    repoURL: https://git.example.internal/peakcommerce/platform-config.git
    targetRevision: main
    path: helm/peakcommerce-enterprise
    helm:
      releaseName: peakcommerce-enterprise
      valueFiles:
        - values-prod.yaml
      valuesObject:
        global:
          businessName: peakcommerce-enterprise-suite
          environment: prod
          namespace: peakcommerce-prod
          runAsUser: 10001
          runAsGroup: 10001
          fsGroup: 10001
          runtimeUser: peakcommerce
          primaryRegionMode: active-active
          observability:
            tracingProvider: opentelemetry
            metricsProvider: prometheus
            logsProvider: loki
            correlationKeys:
              - order_id
              - checkout_id
          databases:
            orders: commerce_orders
            promotions: commerce_promotions
            support: support_ops
        services:
          storefront-web:
            enabled: true
            serviceName: storefront-web
            containerPort: 3000
            servicePort: 80
            ingress:
              enabled: true
              className: nginx
              annotations:
                nginx.ingress.kubernetes.io/proxy-read-timeout: "30"
                nginx.ingress.kubernetes.io/proxy-send-timeout: "30"
              hosts:
                - host: www.peakcommerce.example.com
                  paths:
                    - path: /
                      pathType: Prefix
            config:
              dataPaths:
                - /srv/peakcommerce/storefront-web
                - /etc/peakcommerce/storefront-web
                - /var/log/peakcommerce/storefront-web
          checkout-api:
            enabled: true
            serviceName: checkout-api
            containerPort: 8080
            servicePort: 8080
            config:
              dataPaths:
                - /srv/peakcommerce/checkout-api
                - /etc/peakcommerce/checkout-api
                - /var/log/peakcommerce/checkout-api
              consistency:
                orderWriteMode: home-region-pinned
          order-orchestrator:
            enabled: true
            serviceName: order-orchestrator
            containerPort: 8080
            servicePort: 8080
            config:
              dataPaths:
                - /srv/peakcommerce/order-orchestrator
                - /etc/peakcommerce/order-orchestrator
                - /var/lib/peakcommerce/order-orchestrator
                - /var/log/peakcommerce/order-orchestrator
          inventory-sync:
            enabled: true
            serviceName: inventory-sync
            containerPort: 8080
            servicePort: 8080
            config:
              dataPaths:
                - /srv/peakcommerce/inventory-sync
                - /etc/peakcommerce/inventory-sync
                - /var/lib/peakcommerce/inventory-sync
                - /var/log/peakcommerce/inventory-sync
          promotion-engine:
            enabled: true
            serviceName: promotion-engine
            containerPort: 8080
            servicePort: 8080
            config:
              dataPaths:
                - /srv/peakcommerce/promotion-engine
                - /etc/peakcommerce/promotion-engine
                - /var/log/peakcommerce/promotion-engine
              runtimeSlo:
                promotionEvaluationP95Ms: 80
          support-console:
            enabled: true
            serviceName: support-console
            containerPort: 8080
            servicePort: 8080
            ingress:
              enabled: false
            config:
              dataPaths:
                - /srv/peakcommerce/support-console
                - /etc/peakcommerce/support-console
                - /var/log/peakcommerce/support-console
              audit:
                immutableEventsRequired: true
                operatorIdentityRequired: true
        rollout:
          strategy: staged
          maxUnavailable: 0
          maxSurge: 1
          verification:
            required: true
            checks:
              - storefront-web
              - checkout-api
              - order-orchestrator
              - inventory-sync
              - promotion-engine
              - support-console
        rollback:
          enabled: true
          revisionHistoryLimit: 10
          triggers:
            - degraded-health
            - failed-sync
            - failed-post-sync-verification
          preserveLastKnownGood: true
  syncPolicy:
    automated:
      prune: false
      selfHeal: false
    syncOptions:
      - CreateNamespace=true
      - PruneLast=true
      - RespectIgnoreDifferences=true
      - ApplyOutOfSyncOnly=true
  revisionHistoryLimit: 10
  ignoreDifferences:
    - group: apps
      kind: Deployment
      jsonPointers:
        - /spec/replicas
  info:
    - name: deployment-model
      value: GitOps staged rollout with health verification and rollback manifests
    - name: traffic-profile
      value: 8-12x read traffic and 4-6x checkout submission volume during peak campaigns
    - name: security-boundary
      value: storefront-web internet-exposed behind WAF/CDN; internal APIs private via SSO/VPN
