      refresh-mode: kafka-and-poll
      poll-interval: 45s
      full-snapshot-cron: "0 */10 * * * *"
      cache-version-key: promo:rules:version:prod
      hot-rule-sets: [flash-sale, cart-threshold, coupon-eligibility, shipping-discount]
      eligibility:
        block-expired-campaigns: true
        require-customer-segment-match: true
        enforce-marketplace-exclusions: true
    redis:
      key-prefix: "peak:promo:prod:"
      hot-state-ttl: 90s
      coupon-usage-ttl: 15m
      campaign-throttle-ttl: 5s
      stale-rule-ttl: 10m
      negative-cache-ttl: 20s
      topology: standalone
      keys:
        rule-set: "peak:promo:prod:ruleset:"
        campaign-state: "peak:promo:prod:campaign:"
        coupon-usage: "peak:promo:prod:coupon:"
        checkout-eval: "peak:promo:prod:checkout:"
        throttle: "peak:promo:prod:throttle:"
    rate-limit:
      enabled: true
      strategy: redis-token-bucket
      fail-open-on-redis-timeout: true
      dimensions: [campaign_id, coupon_code, client_ip_hash]
      defaults:
        replenish-rate-per-second: 400
        burst-capacity: 800
        requested-tokens: 1
      policies:
        flash-sale:
          match:
            campaign-tags: [flash-sale, holiday-doorbuster]
          replenish-rate-per-second: 1200
          burst-capacity: 2400
          requested-tokens: 1
        coupon-validate:
          match:
            operation: coupon-validate
          replenish-rate-per-second: 250
          burst-capacity: 500
          requested-tokens: 1
        checkout-price:
          match:
            operation: checkout-price
          replenish-rate-per-second: 900
          burst-capacity: 1800
          requested-tokens: 1
        support-preview:
          match:
            channel: support-console
          replenish-rate-per-second: 80
          burst-capacity: 160
          requested-tokens: 1
    throttling:
      peak-event-mode:
        enabled: true
        state-key: peak:promo:prod:mode
        default-mode: normal
        modes:
          normal:
            max-concurrent-evaluations: 600
            allow-best-effort-fallback: false
          elevated:
            max-concurrent-evaluations: 900
            allow-best-effort-fallback: true
          emergency:
            max-concurrent-evaluations: 1200
            allow-best-effort-fallback: true
            disable-nonessential-banners: true
            skip-low-priority-segment-lookups: true
    kafka:
      topics:
        promotion-rule-events: commerce.promotion.rule.events
        promotion-audit-events: commerce.promotion.audit.events
        checkout-pricing-events: commerce.checkout.pricing.events
      producer:
        acks: all
        retries: 5
        linger-ms: 5
        batch-size: 32768
        compression-type: zstd
      consumer:
        rule-refresh-concurrency: 6
        audit-publish-enabled: true
    audit:
      emit-evaluation-events: true
      emit-admin-overrides: true
      immutable-topic: commerce.promotion.audit.events
      include-operator-identity-for-support-actions: true
    dependencies:
      checkout-api:
        base-url: http://checkout-api.peakcommerce.svc.cluster.local:8080
        connect-timeout-ms: 80
        read-timeout-ms: 120
      storefront-web:
        trusted-forwarded-header: x-forwarded-for
      support-console:
        allowed: true
        require-sso-assertion-header: true

