@RestController
@RequestMapping("/api/v1/checkout")
@Validated
public class IdempotentOrderController {

    private static final Logger log = LoggerFactory.getLogger(IdempotentOrderController.class);
    private static final String IDEMPOTENCY_HEADER = "Idempotency-Key";
    private static final String CHECKOUT_ID_HEADER = "X-Checkout-Id";
    private static final String ORDER_ID_HEADER = "X-Order-Id";
    private static final String CORRELATION_HEADER = "X-Correlation-Id";

    private final IdempotencyService idempotencyService;
    private final OrderSubmissionService orderSubmissionService;

    public IdempotentOrderController(
            IdempotencyService idempotencyService,
            OrderSubmissionService orderSubmissionService) {
        this.idempotencyService = idempotencyService;
        this.orderSubmissionService = orderSubmissionService;
    }

    @PostMapping("/orders")
    public ResponseEntity<SubmitOrderResponse> submitOrder(
            @RequestHeader(IDEMPOTENCY_HEADER) @NotBlank String idempotencyKey,
            @RequestHeader(value = CHECKOUT_ID_HEADER, required = false) String checkoutIdHeader,
            @RequestHeader(value = CORRELATION_HEADER, required = false) String correlationIdHeader,
            @Valid @RequestBody SubmitOrderRequest request,
            HttpServletRequest httpRequest) {

        String checkoutId = firstNonBlank(checkoutIdHeader, request.checkoutId());
        String correlationId = firstNonBlank(correlationIdHeader, currentTraceId().orElse(null), checkoutId);
        String payloadHash = payloadHash(request);
        String clientFingerprint = clientFingerprint(httpRequest, request);

        IdempotencyDecision decision = idempotencyService.evaluate(
                idempotencyKey,
                checkoutId,
                payloadHash,
                clientFingerprint);

        if (decision.isReplay()) {
            SubmitOrderResponse cached = decision.cachedResponse()
                    .orElseThrow(() -> new IllegalStateException("Replay decision without cached response"));
            log.info(
                    "Returning cached order submission response for checkout_id={}, order_id={}, idempotency_key={}, correlation_id={}",
                    checkoutId,
                    cached.orderId(),
                    safeKey(idempotencyKey),
                    correlationId);
            return responseForReplay(cached, correlationId);
        }

        if (decision.isConflict()) {
            log.warn(
                    "Idempotency conflict detected for checkout_id={}, idempotency_key={}, correlation_id={}, reason={}",
                    checkoutId,
                    safeKey(idempotencyKey),
                    correlationId,
                    decision.reason());
            throw new IdempotencyConflictException(
                    "Idempotency key already used with a different request payload");
        }

        if (decision.isInFlight()) {
            log.info(
                    "Duplicate in-flight order submission blocked for checkout_id={}, idempotency_key={}, correlation_id={}",
                    checkoutId,
                    safeKey(idempotencyKey),
                    correlationId);
            return ResponseEntity.status(HttpStatus.ACCEPTED)
                    .header(CORRELATION_HEADER, correlationId)
                    .body(SubmitOrderResponse.pending(
                            checkoutId,
                            "ORDER_SUBMISSION_IN_PROGRESS",
                            OffsetDateTime.now()));
        }

        OrderSubmissionResult result = orderSubmissionService.submitOrder(
                request,
                idempotencyKey,
                checkoutId,
                correlationId);

        SubmitOrderResponse response = SubmitOrderResponse.accepted(
                result.orderId(),
                result.checkoutId(),
                result.status(),
                result.homeRegion(),
                result.submittedAt(),
                result.message());

        idempotencyService.recordSuccess(
                idempotencyKey,
                checkoutId,
                payloadHash,
                clientFingerprint,
                response);

        log.info(
                "Order submitted successfully for checkout_id={}, order_id={}, home_region={}, idempotency_key={}, correlation_id={}",
                result.checkoutId(),
                result.orderId(),
                result.homeRegion(),
                safeKey(idempotencyKey),
                correlationId);

        return ResponseEntity.created(URI.create("/api/v1/orders/" + result.orderId()))
                .header(CORRELATION_HEADER, correlationId)
                .header(ORDER_ID_HEADER, result.orderId())
                .body(response);
    }

    @ExceptionHandler(IdempotencyConflictException.class)
    public ResponseEntity<Map<String, Object>> handleIdempotencyConflict(IdempotencyConflictException ex) {
        String correlationId = currentTraceId().orElse("unknown");
        return ResponseEntity.status(HttpStatus.CONFLICT)
                .header(CORRELATION_HEADER, correlationId)
                .body(Map.of(
                        "error", "IDEMPOTENCY_CONFLICT",
                        "message", ex.getMessage(),
                        "correlation_id", correlationId,
                        "timestamp", OffsetDateTime.now().toString()));
    }

    private ResponseEntity<SubmitOrderResponse> responseForReplay(
            SubmitOrderResponse cached,
            String correlationId) {
        ResponseEntity.BodyBuilder builder = HttpStatus.ACCEPTED.equals(HttpStatus.valueOf(202))
                ? ResponseEntity.status(HttpStatus.OK)
                : ResponseEntity.ok();
        return builder
                .header(CORRELATION_HEADER, correlationId)
                .header(ORDER_ID_HEADER, nullSafe(cached.orderId()))
                .header(HttpHeaders.CACHE_CONTROL, "no-store")
                .body(cached.withReplay(true));
    }

    private String payloadHash(SubmitOrderRequest request) {
        String canonical = String.join("|",
                nullSafe(request.checkoutId()),
                nullSafe(request.customerId()),
                nullSafe(request.currency()),
                String.valueOf(request.items() == null ? 0 : request.items().size()),
                String.valueOf(request.totalAmount()),
                nullSafe(request.shippingAddressChecksum()),
                nullSafe(request.billingAddressChecksum()),
                nullSafe(request.paymentMethodRef()),
                nullSafe(request.promotionContextVersion()));
        return DigestUtils.md5DigestAsHex(canonical.getBytes());
    }

    private String clientFingerprint(HttpServletRequest httpRequest, SubmitOrderRequest request) {
        String remoteAddr = Optional.ofNullable(httpRequest.getHeader("X-Forwarded-For"))
                .filter(StringUtils::isNotBlank)
                .map(v -> v.split(",")[0].trim())
                .orElse(httpRequest.getRemoteAddr());
        String userAgent = Optional.ofNullable(httpRequest.getHeader(HttpHeaders.USER_AGENT)).orElse("unknown");
        return DigestUtils.md5DigestAsHex(
                (remoteAddr + "|" + userAgent + "|" + nullSafe(request.customerId())).getBytes());
    }

    private Optional<String> currentTraceId() {
        Span span = Span.current();
        if (span == null || !span.getSpanContext().isValid()) {
            return Optional.empty();
        }
        return Optional.of(span.getSpanContext().getTraceId());
    }

    private String firstNonBlank(String... values) {
        for (String value : values) {
            if (StringUtils.isNotBlank(value)) {
                return value;
            }
        }
        return null;
    }

    private String safeKey(String raw) {
        if (raw == null || raw.length() < 8) {
            return "redacted";
        }
        return raw.substring(0, 4) + "..." + raw.substring(raw.length() - 4);
    }

    private String nullSafe(String value) {
        return value == null ? "" : value;
    }

    public static class IdempotencyConflictException extends RuntimeException {
        public IdempotencyConflictException(String message) {
            super(message);
        }
    }
}
